const rawResponse = $json.output?.[0]?.content?.[0]?.text || '';

let parsed;
try {
  const jsonMatch = rawResponse.match(/```json\s*([\s\S]*?)```/) || [null, rawResponse];
  const cleaned = jsonMatch[1].trim();
  const objMatch = cleaned.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(objMatch ? objMatch[0] : cleaned);
} catch (e) {
  return [{ json: { error: true, message: 'Failed to parse tasks: ' + e.message, raw: rawResponse.slice(0, 500) } }];
}

const now = Date.now();
const staticData = $getWorkflowStaticData('global');
if (!staticData.pending_actions) staticData.pending_actions = {};

const SAFE_TYPES = ['site_change'];
const tasks = (parsed.tasks || []).map((task, i) => {
  const action_id = `seo_action_${now}_${i}`;
  const auto_executable = SAFE_TYPES.includes(task.type) && task.risk_level !== 'high';
  const action = {
    action_id, created_at: new Date().toISOString(), type: task.type,
    status: 'pending', risk_level: task.risk_level || 'medium',
    auto_executable, site_id: task.site_id || 'all',
    title: task.title, description: task.description,
    change_target: task.change_target || null,
    change_method: task.change_method || null,
    search_pattern: task.search_pattern || null,
    replacement: task.replacement || null,
    brief_item: task.brief_item || null,
    approved_at: null, executed_at: null, execution_result: null,
  };
  staticData.pending_actions[action_id] = action;
  return action;
});

return [{ json: {
  success: true, tasks_created: tasks.length,
  summary: parsed.summary || '',
  skipped: parsed.skipped_items || [],
  tasks: tasks.map(t => ({ action_id: t.action_id, type: t.type, title: t.title, site_id: t.site_id, risk_level: t.risk_level, auto_executable: t.auto_executable })),
} }];

const staticData = $getWorkflowStaticData('global');
const actions = Object.values(staticData.pending_actions || {});
const log = staticData.action_log || [];
actions.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
const summary = {
  pending: actions.filter(a => a.status === 'pending').length,
  approved: actions.filter(a => a.status === 'approved').length,
  completed: log.filter(a => a.status === 'completed').length,
  dismissed: log.filter(a => a.status === 'dismissed').length,
};
return [{ json: { summary, actions, recent_log: log.slice(0, 10) } }];

const body = $json.body || $json;
const { action_id } = body;
if (!action_id) return [{ json: { error: true, message: 'Missing action_id' } }];
const staticData = $getWorkflowStaticData('global');
const action = (staticData.pending_actions || {})[action_id];
if (!action) return [{ json: { error: true, message: 'Action not found' } }];
if (action.status !== 'pending') return [{ json: { error: true, message: `Action is ${action.status}` } }];
action.status = 'approved';
action.approved_at = new Date().toISOString();
return [{ json: { success: true, action_id, title: action.title, status: 'approved', auto_executable: action.auto_executable } }];

const body = $json.body || $json;
const { action_id, status: requestedStatus } = body;
if (!action_id) return [{ json: { error: true, message: 'Missing action_id' } }];
const staticData = $getWorkflowStaticData('global');
const action = (staticData.pending_actions || {})[action_id];
if (!action) return [{ json: { error: true, message: 'Action not found' } }];
const finalStatus = requestedStatus === 'completed' ? 'completed' : 'dismissed';
action.status = finalStatus;
if (!staticData.action_log) staticData.action_log = [];
staticData.action_log.unshift({ ...action, executed_at: new Date().toISOString() });
staticData.action_log = staticData.action_log.slice(0, 50);
delete staticData.pending_actions[action_id];
return [{ json: { success: true, action_id, title: action.title, status: finalStatus } }];

const body = $json.body || $json;
const { action_id } = body;
if (!action_id) return [{ json: { error: true, message: 'Missing action_id' } }];
const staticData = $getWorkflowStaticData('global');
const action = (staticData.pending_actions || {})[action_id];
if (!action) return [{ json: { error: true, message: 'Action not found' } }];
if (action.status !== 'approved') return [{ json: { error: true, message: `Must be approved first (currently ${action.status})` } }];
if (!action.auto_executable) {
  return [{ json: { error: false, human_gated: true, message: `This ${action.type} action requires manual implementation.`, action } }];
}
const SITE_MAP = {
  sinabarimd: { domain: 'sinabarimd.com', deployPath: '/srv/sites/sinabarimd', verifyUrl: 'https://sinabarimd.com' },
  sinabari_net: { domain: 'sinabari.net', deployPath: '/srv/sites/sinabari-net', verifyUrl: 'https://sinabari.net' },
  sinabariplasticsurgery: { domain: 'sinabariplasticsurgery.com', deployPath: '/srv/sites/sinabariplasticsurgery', verifyUrl: 'https://sinabariplasticsurgery.com' },
};
const siteConfig = SITE_MAP[action.site_id];
if (!siteConfig) return [{ json: { error: true, message: 'Unknown site: ' + action.site_id } }];
return [{ json: { action, siteConfig, fetch_url: 'https://' + siteConfig.domain + '/' } }];

const upstream = $('Load Action').first().json;
const action = upstream.action;
const siteConfig = upstream.siteConfig;
const currentHtml = typeof $json.data === 'string' ? $json.data : ($json || '');

if (!currentHtml || currentHtml.length < 100) {
  return [{ json: { error: true, message: 'Could not fetch current page HTML' } }];
}

// Apply the change
let updatedHtml = currentHtml;
if (action.change_method === 'replace' && action.search_pattern && action.replacement) {
  if (updatedHtml.includes(action.search_pattern)) {
    updatedHtml = updatedHtml.replace(action.search_pattern, action.replacement);
  } else {
    return [{ json: { error: true, message: 'Search pattern not found in current HTML: ' + action.search_pattern.slice(0, 100) } }];
  }
} else if (action.change_method === 'inject_before' && action.search_pattern && action.replacement) {
  if (updatedHtml.includes(action.search_pattern)) {
    updatedHtml = updatedHtml.replace(action.search_pattern, action.replacement + action.search_pattern);
  } else {
    return [{ json: { error: true, message: 'Injection point not found' } }];
  }
} else if (action.change_method === 'inject_after' && action.search_pattern && action.replacement) {
  if (updatedHtml.includes(action.search_pattern)) {
    updatedHtml = updatedHtml.replace(action.search_pattern, action.search_pattern + action.replacement);
  } else {
    return [{ json: { error: true, message: 'Injection point not found' } }];
  }
} else {
  return [{ json: { error: true, message: 'Missing change_method, search_pattern, or replacement' } }];
}

if (updatedHtml === currentHtml) {
  return [{ json: { error: true, message: 'No change detected — replacement same as original' } }];
}
if (updatedHtml.length < currentHtml.length * 0.8) {
  return [{ json: { error: true, message: 'Safety halt: HTML shrunk by ' + Math.round((1 - updatedHtml.length / currentHtml.length) * 100) + '%' } }];
}

// Build deploy payload — homepage only for v1
// We need to also include styles.css and articles to avoid full-sync wipe
return [{ json: {
  updatedHtml,
  action,
  siteConfig,
  styles_url: 'https://' + siteConfig.domain + '/styles.css',
  articles_index_url: 'https://' + siteConfig.domain + '/articles/index.html',
} }];

const ctx = $('Apply Change and Deploy').first().json;
const stylesResp = $('Fetch Styles').first().json;
const articlesIdxResp = $json;

const action = ctx.action;
const sc = ctx.siteConfig;

const files = [{ path: 'index.html', content: ctx.updatedHtml }];

const stylesCss = typeof stylesResp.data === 'string' ? stylesResp.data : null;
if (stylesCss && stylesCss.length > 10) {
  files.push({ path: 'styles.css', content: stylesCss });
}

const articlesIdx = typeof articlesIdxResp.data === 'string' ? articlesIdxResp.data : null;
if (articlesIdx && articlesIdx.length > 10) {
  files.push({ path: 'articles/index.html', content: articlesIdx });
  // Parse article slugs from the index and note them
  const slugs = [...articlesIdx.matchAll(/href="([^"]*\.html)"/g)].map(m => m[1]).filter(s => s !== 'index.html');
  // We'll fetch these article pages in the deploy step
  // For now, store slugs for reference
}

// For sinabarimd.com, also include dashboard.html if it exists
if (action.site_id === 'sinabarimd') {
  // dashboard.html needs to be preserved — fetch it
  files.push({ path: '__fetch_dashboard', content: 'https://' + sc.domain + '/dashboard.html' });
}

return [{ json: {
  deploy_payload: { domain: sc.domain, deployPath: sc.deployPath, verifyUrl: sc.verifyUrl, release_id: 'seo-impl-' + action.action_id, files },
  action_id: action.action_id,
  site_id: action.site_id,
} }];

// For v1, we flag that execution needs the full file fetch
// and return instructions rather than deploying automatically.
// This is safer given the full-sync constraint.
const { deploy_payload, action_id, site_id } = $json;
const staticData = $getWorkflowStaticData('global');
const action = staticData.pending_actions[action_id];

// Mark as completed (the change was validated, operator can deploy manually or we can enhance later)
action.status = 'completed';
action.executed_at = new Date().toISOString();
action.execution_result = {
  validated: true,
  files_count: deploy_payload.files.length,
  message: 'Change validated. Deploy payload prepared.',
};

if (!staticData.action_log) staticData.action_log = [];
staticData.action_log.unshift({ ...action });
staticData.action_log = staticData.action_log.slice(0, 50);
delete staticData.pending_actions[action_id];

return [{ json: {
  success: true,
  action_id,
  site_id,
  title: action.title,
  status: 'completed',
  message: 'Change validated and staged. Full deploy requires article file preservation — use dashboard Publish or manual deploy.',
} }];
